            var request = new System.Net.Http.HttpRequestMessage(System.Net.Http.HttpMethod.Get, $"{baseUrl}/fixtures/compression_brotli_only/compression/brotli");
            request.Headers.Add("Accept-Encoding", "br");
            var response = await client.SendAsync(request);
            Assert.Equal(200, (int)response.StatusCode);
